// ---------------------------------------------------------------------------
// Classify user intent from their Telegram message using regex.
// No LLM call needed — fast and deterministic for common queries.
// Intents: temp | cpu | memory | disk | full
// ---------------------------------------------------------------------------
const msg = ($input.first().json.message?.text || '').toLowerCase().trim();

const rules = [
  { intent: 'temp',   pattern: /\b(temp|hot|heat|cool|overh|burn|thermal|degree|°)/ },
  { intent: 'cpu',    pattern: /\b(cpu|processor|load|compute|utiliz|usage.*cpu|cpu.*usage)/ },
  { intent: 'memory', pattern: /\b(mem|ram|swap|heap|out.of.memory|oom)/ },
  { intent: 'disk',   pattern: /\b(disk|storage|space|volume|lvm|partition|full|free.space)/ },
];

let intent = 'full'; // default: full report
for (const rule of rules) {
  if (rule.pattern.test(msg)) {
    intent = rule.intent;
    break;
  }
}

return [{ json: { intent, userMessage: msg } }];

const t = $input.first().json?.data || {};

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const cpu  = t['k10temp-pci-00c3']?.Tctl?.temp1_input  ?? 'N/A';
const gpu  = t['amdgpu-pci-0500']?.edge?.temp1_input   ?? 'N/A';
const nvme = t['nvme-pci-0400']?.Composite?.temp1_input ?? 'N/A';

const cpuSt  = label(cpu,  85, 95);
const nvmeSt = label(nvme, 70, 80);

const overallSt = [cpuSt, nvmeSt].includes('CRIT') ? 'CRIT'
  : [cpuSt, nvmeSt].includes('WARN') ? 'WARN' : 'OK';

const phrase = {
  OK:   'All temperatures are within safe limits.',
  WARN: 'Some components are running warm — keep an eye on it.',
  CRIT: 'Temperature critically high — check cooling immediately.'
}[overallSt];

const text =
`ἲ1️ *Temperatures*
CPU: ${cpu}°C [${cpuSt}] | GPU: ${gpu}°C | NVMe: ${nvme}°C [${nvmeSt}]
_${phrase}_`;

return [{ json: { text } }];

const s = $input.first().json?.data || {};
const intent = $('Classify Intent').first().json.intent;

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const cpuPct = ((s.cpu || 0) * 100).toFixed(1);
const cpuSt  = label(cpuPct, 80, 95);
const load   = (s.loadavg || []).join(', ');

const ramPct = s.memory?.total
  ? ((s.memory.used / s.memory.total) * 100).toFixed(1) : 'N/A';
const ramSt  = label(ramPct, 85, 95);
const ramUsedGB = s.memory?.used  ? (s.memory.used  / 1073741824).toFixed(1) : '?';
const ramTotGB  = s.memory?.total ? (s.memory.total / 1073741824).toFixed(1) : '?';
const swapPct   = s.swap?.total
  ? ((s.swap.used / s.swap.total) * 100).toFixed(1) : '0.0';

let text;
if (intent === 'cpu') {
  const phrase = {
    OK:   'CPU is idle and happy.',
    WARN: 'CPU load is elevated — something is busy.',
    CRIT: 'CPU is under very heavy load.'
  }[cpuSt];
  text = `Ὃb *CPU*
Usage: ${cpuPct}% [${cpuSt}] | Load avg: ${load}
_${phrase}_`;
} else {
  const phrase = {
    OK:   'Memory usage is healthy.',
    WARN: 'Memory is getting high — check running services.',
    CRIT: 'Running critically low on RAM.'
  }[ramSt];
  text = `ᾞ0 *Memory*
RAM: ${ramUsedGB} / ${ramTotGB} GB (${ramPct}%) [${ramSt}] | Swap: ${swapPct}%
_${phrase}_`;
}

return [{ json: { text } }];

const disk = $input.first().json?.data || [];

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const lines = disk.map(d => {
  const pct = (d.used_fraction * 100).toFixed(1);
  const freeGB = (d.avail / 1073741824).toFixed(1);
  return `- ${d.storage} (${d.type}): ${pct}% used, ${freeGB} GB free [${label(pct, 80, 90)}]`;
}).join('\n');

const worst = disk.reduce((acc, d) => Math.max(acc, d.used_fraction * 100), 0);
const worstSt = label(worst, 80, 90);

const phrase = {
  OK:   'Storage is in good shape.',
  WARN: 'Some pools are getting full — consider cleaning up.',
  CRIT: 'Storage critically low — act now.'
}[worstSt];

const text = `Ὃe *Storage*
${lines}
_${phrase}_`;

return [{ json: { text } }];

// Extract first clean sentence from LLM, append under structured data.
const llmRaw = ($input.first().json.response || '').trim();
const firstLine = llmRaw.split(/[\n]/)[0].trim();
// Strip any echoed 'Sentence:' prefix the LLM might produce
const sentence = firstLine.replace(/^sentence[:\s]*/i, '').trim();

const formattedText = $('Aggregate Full').first().json.formattedText || '';

const text = sentence
  ? `${formattedText}\n_${sentence}_`
  : formattedText;

return [{ json: { text } }];

const items = $input.all();
const status = items[0]?.json?.data || {};
const temp   = items[1]?.json?.data || {};
const disk   = items[2]?.json?.data || [];

function label(val, w, c) {
  const n = parseFloat(val);
  if (isNaN(n)) return '?';
  return n >= c ? 'CRIT' : n >= w ? 'WARN' : 'OK';
}

const cpuPct     = ((status.cpu || 0) * 100).toFixed(1);
const ramPct     = status.memory?.total ? ((status.memory.used / status.memory.total) * 100).toFixed(1) : 'N/A';
const rootPct    = status.rootfs?.total ? ((status.rootfs.used / status.rootfs.total) * 100).toFixed(1) : 'N/A';
const uptimeDays = status.uptime ? (status.uptime / 86400).toFixed(1) : 'N/A';

const cpuTemp  = temp['k10temp-pci-00c3']?.Tctl?.temp1_input  ?? 'N/A';
const gpuTemp  = temp['amdgpu-pci-0500']?.edge?.temp1_input   ?? 'N/A';
const nvmeTemp = temp['nvme-pci-0400']?.Composite?.temp1_input ?? 'N/A';

const cpuSt   = label(cpuPct,  80, 95);
const ramSt   = label(ramPct,  85, 95);
const rootSt  = label(rootPct, 80, 90);
const cpuTSt  = label(cpuTemp, 85, 95);
const nvmeTSt = label(nvmeTemp, 70, 80);

const storageLines = disk.map(d =>
  `- ${d.storage} (${d.type}): ${(d.used_fraction * 100).toFixed(1)}% used, ${(d.avail / 1073741824).toFixed(1)} GB free [${label(d.used_fraction * 100, 80, 90)}]`
).join('\n');

const warns = [];
if (cpuSt   !== 'OK') warns.push(`CPU ${cpuPct}%`);
if (ramSt   !== 'OK') warns.push(`RAM ${ramPct}%`);
if (rootSt  !== 'OK') warns.push(`root disk ${rootPct}%`);
if (cpuTSt  !== 'OK') warns.push(`CPU temp ${cpuTemp}°C`);
if (nvmeTSt !== 'OK') warns.push(`NVMe ${nvmeTemp}°C`);
disk.forEach(d => {
  if (label(d.used_fraction * 100, 80, 90) !== 'OK')
    warns.push(`${d.storage} ${(d.used_fraction * 100).toFixed(0)}%`);
});
const warnsText = warns.length ? warns.join(', ') : 'None';

const formattedText =
`Ὄa *Proxmox* | uptime: ${uptimeDays}d
CPU: ${cpuPct}% [${cpuSt}] | RAM: ${ramPct}% [${ramSt}] | Root: ${rootPct}% [${rootSt}]
Temp: CPU ${cpuTemp}°C [${cpuTSt}] | GPU ${gpuTemp}°C | NVMe ${nvmeTemp}°C [${nvmeTSt}]
Storage:
${storageLines}
⚠️ Warnings: ${warnsText}`;

// LLM only writes one casual sentence
const prompt = `Proxmox homelab stats: CPU ${cpuPct}%, RAM ${ramPct}%, temps ${cpuTemp}°C, warnings ${warnsText}.
Write one casual sentence (under 12 words, no numbers) describing the overall health.
Sentence:`;

return [{ json: { formattedText, prompt } }];
